    if (customPath) {
      this.tokenDir = customPath;
      this.tokenFile = path.join(customPath, 'tokens.json');
    } else {
      this.tokenDir = path.join(os.homedir(), '.config', 'mcp-tiktok');
      this.tokenFile = path.join(this.tokenDir, 'tokens.json');
    }
  }

